 1	import React, { FC } from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import { K8sResourceCommon } from '@openshift-console/dynamic-plugin-sdk';
 5	import {
 6	  Breadcrumb,
 7	  BreadcrumbItem,
 8	  DescriptionListDescription,
 9	  DescriptionListGroup,
10	  DescriptionListTermHelpText,
11	  DescriptionListTermHelpTextButton,
12	  Popover,
13	} from '@patternfly/react-core';
14	import { useNMStateTranslation } from '@utils/hooks/useNMStateTranslation';
15	
16	import OwnerReferences from '../OwnerReferences/OwnerReferences';
17	
18	type OwnerDetailsItemProps = {
19	  obj: K8sResourceCommon;
20	};
21	
22	const OwnerDetailsItem: FC<OwnerDetailsItemProps> = ({ obj }) => {
23	  const { t } = useNMStateTranslation();
24	
25	  return (
26	    <DescriptionListGroup className="pf-c-description-list__group">
27	      <DescriptionListTermHelpText className="pf-c-description-list__term">
28	        <Popover
29	          bodyContent={
30	            <Trans t={t}>
31	              <div>
32	                List of objects depended by this object. If ALL objects in the list have been
33	                deleted, this object will be garbage collected. If this object is managed by a
34	                controller, then an entry in this list will point to this controller, with the
35	                controller field set to true. There cannot be more than one managing controller.
36	              </div>
37	              <Breadcrumb className="margin-top">
38	                <BreadcrumbItem>{{ kind: obj?.kind }}</BreadcrumbItem>
39	                <BreadcrumbItem>metadata</BreadcrumbItem>
40	                <BreadcrumbItem>ownerReferences</BreadcrumbItem>
41	              </Breadcrumb>
42	            </Trans>
43	          }
44	          hasAutoWidth
45	          headerContent={t('Owner')}
46	          maxWidth="30rem"
47	        >
48	          <DescriptionListTermHelpTextButton className="pf-c-description-list__text">
49	            {t('Owner')}
50	          </DescriptionListTermHelpTextButton>
51	        </Popover>
52	      </DescriptionListTermHelpText>
53	      <DescriptionListDescription className="pf-c-description-list__description">
54	        <OwnerReferences obj={obj} />
55	      </DescriptionListDescription>
56	    </DescriptionListGroup>
57	  );
58	};
59	
60	export default OwnerDetailsItem;

